import{c as e,i as t,n,o as r,r as i,s as a,t as o}from"./app-CsVfPmwr.js";var s=JSON.parse(`{"path":"/brands/frederique-constant.html","title":"Frédérique Constant","lang":"ko-KR","frontmatter":{"description":"Frédérique Constant Frédérique Constant(프레드릭 콘스탄트)는 1988년 스위스 제네바에서 피터 스타스(Peter Stas)와 알레타 스타스(Aletta Stas) 부부가 설립한 독립 시계 브랜드다. 브랜드명은 설립자 증조할머니와 증조할아버지의 이름에서 각각 따왔다. &quot;접근 가...","head":[["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"Frédérique Constant\\",\\"image\\":[\\"https://kmbzn.com/images/og.png\\"],\\"dateModified\\":\\"2026-06-12T20:48:55.000Z\\",\\"author\\":[]}"],["meta",{"property":"og:url","content":"https://kmbzn.com/brands/frederique-constant.html"}],["meta",{"property":"og:title","content":"Frédérique Constant"}],["meta",{"property":"og:description","content":"Frédérique Constant Frédérique Constant(프레드릭 콘스탄트)는 1988년 스위스 제네바에서 피터 스타스(Peter Stas)와 알레타 스타스(Aletta Stas) 부부가 설립한 독립 시계 브랜드다. 브랜드명은 설립자 증조할머니와 증조할아버지의 이름에서 각각 따왔다. &quot;접근 가..."}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:image","content":"https://kmbzn.com/images/og.png"}],["meta",{"property":"og:locale","content":"ko-KR"}],["meta",{"property":"og:updated_time","content":"2026-06-12T20:48:55.000Z"}],["meta",{"property":"article:modified_time","content":"2026-06-12T20:48:55.000Z"}]]},"git":{"createdTime":1781277665000,"updatedTime":1781297335000,"contributors":[{"name":"kmbzn","username":"kmbzn","email":"kmbzn24@gmail.com","commits":2,"url":"https://github.com/kmbzn"},{"name":"Claude Sonnet 4.6","username":"","email":"noreply@anthropic.com","commits":1}],"changelog":[{"hash":"47b5aed4ca177bf4af7be2a57306ea9a97ab434f","time":1781297335000,"email":"kmbzn24@gmali.com","author":"kmbzn","message":"0613_final"},{"hash":"8227255e0018b0d2c63e50076b5cc2406a472c1d","time":1781277665000,"email":"kmbzn24@gmail.com","author":"kmbzn","message":"feat: add SEO plugins, new articles (Baroque/FC/fidget), sidebar updates","coAuthors":[{"name":"Claude Sonnet 4.6","email":"noreply@anthropic.com"}]}]},"filePathRelative":"brands/frederique-constant.md","autoDesc":true}`),c={name:`frederique-constant.md`},l={class:`print-section`};function u(o,s,c,u,d,f){let p=e(`DateMeta`);return a(),i(`div`,null,[n(`section`,l,[s[0]||=n(`h1`,{id:`frederique-constant`,tabindex:`-1`},[n(`a`,{class:`header-anchor`,href:`#frederique-constant`},[n(`span`,null,`Frédérique Constant`)])],-1),r(p),s[1]||=n(`p`,null,`Frédérique Constant(프레드릭 콘스탄트)는 1988년 스위스 제네바에서 피터 스타스(Peter Stas)와 알레타 스타스(Aletta Stas) 부부가 설립한 독립 시계 브랜드다. 브랜드명은 설립자 증조할머니와 증조할아버지의 이름에서 각각 따왔다. "접근 가능한 럭셔리(Accessible Luxury)"를 핵심 포지셔닝으로 삼아, 인하우스 무브먼트를 스위스 명품 브랜드 중 가장 합리적인 가격대에 제공하는 것이 전략적 차별점이다.`,-1)]),s[2]||=t(`<section class="print-section"><h2 id="브랜드-개요" tabindex="-1"><a class="header-anchor" href="#브랜드-개요"><span>브랜드 개요</span></a></h2><table><thead><tr><th>항목</th><th>내용</th></tr></thead><tbody><tr><td>설립</td><td>1988년</td></tr><tr><td>설립자</td><td>Peter Stas, Aletta Stas</td></tr><tr><td>본사</td><td>제네바 Plan-les-Ouates, 스위스</td></tr><tr><td>슬로건</td><td>&quot;Live Your Passion&quot;</td></tr><tr><td>특징</td><td>인하우스 무브먼트, 접근 가능한 스위스 럭셔리</td></tr><tr><td>모기업</td><td>Citizen Watch Group (2016년 인수)</td></tr></tbody></table><p>2016년 일본 시티즌 워치 그룹(Citizen Watch Group)에 인수되었으나, 브랜드 독립성과 제네바 생산 체계는 유지하고 있다.</p></section><section class="print-section"><h2 id="인하우스-무브먼트" tabindex="-1"><a class="header-anchor" href="#인하우스-무브먼트"><span>인하우스 무브먼트</span></a></h2><p>Frédérique Constant의 가장 중요한 강점은 <strong>스위스 럭셔리 시계 중 가장 낮은 가격대에서 인하우스(자체 제작) 무브먼트를 제공한다는 것</strong>이다.</p><p>대부분의 동급 가격대 브랜드들이 ETA 2824나 Sellita SW200 같은 범용 무브먼트를 탑재하는 반면, FC는 자체 칼리버를 설계·제조한다.</p></section><section class="print-section"><h3 id="주요-칼리버" tabindex="-1"><a class="header-anchor" href="#주요-칼리버"><span>주요 칼리버</span></a></h3><table><thead><tr><th>칼리버</th><th>종류</th><th>특징</th></tr></thead><tbody><tr><td>FC-200</td><td>수동감기</td><td>베이직 드레스워치용</td></tr><tr><td>FC-303</td><td>자동감기</td><td>3침 기본 자동</td></tr><tr><td>FC-310</td><td>자동감기</td><td>날짜 창 포함</td></tr><tr><td>FC-700</td><td>자동감기</td><td>연력(Annual Calendar). 31일 달 인식, 2월만 수동 조정</td></tr><tr><td>FC-710</td><td>자동감기</td><td>만년력(Perpetual Calendar). 완전 자동 날짜 조정</td></tr><tr><td>FC-935</td><td>자동감기</td><td>하트비트(오픈워크 다이얼, 밸런스 휠 노출)</td></tr></tbody></table><p>특히 FC-700 연력 무브먼트는 동급 기능 대비 가격이 낮아 칼렌더 시계 입문에 자주 추천된다.</p></section><section class="print-section"><h2 id="주요-컬렉션" tabindex="-1"><a class="header-anchor" href="#주요-컬렉션"><span>주요 컬렉션</span></a></h2></section><section class="print-section"><h3 id="classics-클래식스" tabindex="-1"><a class="header-anchor" href="#classics-클래식스"><span>Classics (클래식스)</span></a></h3><p>브랜드의 상징적인 라인. 아치형 러그, 둥근 케이스, 로마 숫자 또는 인덱스 다이얼의 전통적인 드레스워치 감성이 특징이다.</p><ul><li><strong>Classics Heart Beat</strong>: 6시 방향에 개구부를 두어 밸런스 휠이 보이는 독특한 다이얼</li><li><strong>Classics Business Timer</strong>: 2개의 시간대 동시 표시</li><li><strong>Classics Moonphase</strong>: 문페이즈 기능 포함</li><li>케이스: 스틸 / 로즈골드 PVD</li><li>가격대: CHF 700 ~ 2,000 (약 100만원 ~ 300만원)</li></ul></section><section class="print-section"><h3 id="slimline" tabindex="-1"><a class="header-anchor" href="#slimline"><span>Slimline</span></a></h3><p>얇은 케이스(~5mm)와 미니멀한 다이얼이 특징인 드레스워치 라인. 연력·문페이즈·미닛리피터(Minute Repeater) 등 복잡 기능 버전도 있다. NOMOS Glashütte의 경쟁 포지션으로 자주 언급된다.</p><ul><li>두께: 4.8mm 내외 (기본형)</li><li>무브먼트: FC-200 (수동) / FC-710 (만년력)</li><li>가격대: CHF 800 ~ 3,000</li></ul></section><section class="print-section"><h3 id="runabout" tabindex="-1"><a class="header-anchor" href="#runabout"><span>Runabout</span></a></h3><p>1930~50년대 목제 모터보트에서 영감을 받은 스포티한 라인. 스크류 백(caseback)에 배 문양 조각, 브라운 계열 스트랩이 특징이다. 남성적이고 캐주얼한 감성을 원하는 이들에게 적합하다.</p></section><section class="print-section"><h3 id="persuasion" tabindex="-1"><a class="header-anchor" href="#persuasion"><span>Persuasion</span></a></h3><p>빈티지 감성의 트리컴프(tri-compax) 크로노그래프 라인. 레트로 팬다 다이얼, 빈티지 폰트 등으로 50~60년대 레이싱 시계 감성을 현대적으로 재해석했다.</p></section><section class="print-section"><h2 id="가격대" tabindex="-1"><a class="header-anchor" href="#가격대"><span>가격대</span></a></h2><table><thead><tr><th>라인</th><th>CHF</th><th>KRW (공식 기준)</th></tr></thead><tbody><tr><td>Classics (기본)</td><td>700~</td><td>약 100만원~</td></tr><tr><td>Classics Heart Beat</td><td>1,200~</td><td>약 170만원~</td></tr><tr><td>Slimline (기본)</td><td>800~</td><td>약 120만원~</td></tr><tr><td>Slimline Perpetual</td><td>2,500~</td><td>약 350만원~</td></tr><tr><td>Runabout</td><td>1,000~</td><td>약 140만원~</td></tr></tbody></table></section><section class="print-section"><h2 id="포지셔닝" tabindex="-1"><a class="header-anchor" href="#포지셔닝"><span>포지셔닝</span></a></h2><p>Frédérique Constant는 스위스 시계 시장에서 <strong>진입장벽이 낮은 인하우스 무브먼트 브랜드</strong>라는 명확한 위치를 점한다.</p><table><thead><tr><th>브랜드</th><th>포지션</th><th>특징</th></tr></thead><tbody><tr><td>Longines</td><td>접근 가능한 스위스</td><td>ETA 기반, 스와치 그룹</td></tr><tr><td><strong>Frédérique Constant</strong></td><td>접근 가능한 인하우스</td><td>자체 무브먼트, 독립</td></tr><tr><td>NOMOS Glashütte</td><td>독일 미니멀 인하우스</td><td>바우하우스 디자인</td></tr><tr><td>Tissot</td><td>볼륨 스위스</td><td>다양한 라인, ETA 기반</td></tr><tr><td>Mido</td><td>실용 스위스</td><td>ETA 기반, 스와치 그룹</td></tr></tbody></table><p>NOMOS와 자주 비교되는 브랜드다. NOMOS가 바우하우스 미니멀리즘을 강하게 추구한다면, FC는 보다 클래식하고 전통적인 드레스워치 미학에 가깝다.</p></section><section class="print-section"><h2 id="구매-시-고려사항" tabindex="-1"><a class="header-anchor" href="#구매-시-고려사항"><span>구매 시 고려사항</span></a></h2><ul><li>공식 판매처: 국내 일부 시계 편집숍, 온라인 공식 스토어</li><li>독립 인하우스 브랜드 중 유일하게 CH 700~1,000 구간에 자체 무브먼트 제공</li><li>스와치 그룹(Longines, Omega)이나 LVMH 계열 대비 브랜드 파워는 낮지만 가격 대비 무브먼트 완성도가 높다는 평가</li><li>시티즌 그룹 인수 이후에도 품질 유지에 대한 평가는 대체로 긍정적</li></ul><hr><p><em><a href="https://www.frederique-constant.com" target="_blank" rel="noopener noreferrer">공식 웹사이트</a></em></p></section>`,11)])}var d=o(c,[[`render`,u]]);export{s as _pageData,d as default};